    summary_materials_label:"Materiały", summary_materials_text:"Flipchart, karteczki Post-it, wstępna karta pracy, Ćwiczenia 1 – 2 – 3 – 4, karty ról.",
    summary_equipment_label:"Wyposażenie", summary_equipment_text:"Laptop, projektor, ksero/skaner.",

